This check in setup.py seems to break installation using pip. The install_requires is never reached because of this. Not sure why this section is needed at all because when installing via pip it should normally take care of this missing library and will auto install it.

try:
    from Cython.Distutils import build_ext
except ImportError:
    print('Cython is not installed. Please install Cython first.')
    sys.exit()

```python
import pickle
import time
from esipy.cache import BaseCache

class RedisCache(BaseCache):
    """ BaseCache implementation for Redis cache.

    This cache handler requires the redis package to be installed
    `pip install redis`
    """

    def __init__(self, redis_client):
        """ redis_client must be an instance of redis.Redis"""
        from redis import Redis
        if not isinstance(redis_client, Redis):
            raise TypeError('cache must be an instance of redis.Redis')
        self._r = redis_client

    def get(self, key, default=None):
        value = self._r.get(self._hash(key))
        return pickle.loads(value) if value is not None else default

    def set(self, key, value, timeout=300):
        expire_time = 0 if timeout is None else timeout
        return self._r.set(self._hash(key), pickle.dumps(value), expire_time)

    def invalidate(self, key):
        return self._r.delete(self._hash(key))
```
