For historical reasons we are currently using C API.
Using that, the transformation from `Z3_tactic_apply_result` to `Z3_ast` is rather scary:

```
    long result = tactic_apply(z3context, tseitinTactic, goal);
    apply_result_inc_ref(z3context, result);

    int no_subgoals = apply_result_get_num_subgoals(z3context, result);
    long[] goal_formulas = new long[no_subgoals];

    for (int i=0; i<no_subgoals; i++) {
      long subgoal = apply_result_get_subgoal(z3context, result, i);
      int no_subgoal_f = goal_size(z3context, subgoal);

      long[] subgoal_formulas = new long[no_subgoal_f];
      for (int k=0; k<no_subgoal_f; k++) {
        long f = goal_formula(z3context, subgoal, k);
        inc_ref(z3context, f);
        subgoal_formulas[k] = f;
      }

      long subgoal_f = mk_and(z3context, subgoal_formulas.length,
          subgoal_formulas);
      inc_ref(z3context, subgoal_f);
      // Cleanup.
      for (int k=0; k<no_subgoal_f; k++) {
        dec_ref(z3context, subgoal_formulas[k]);
      }
      goal_formulas[i] = subgoal_f;
    }
    long out_formula = mk_and(z3context, goal_formulas.length, goal_formulas);
    inc_ref(z3context, out_formula);

    // More cleanup.
    for (int i=0; i<no_subgoals; i++) {
      dec_ref(z3context, goal_formulas[i]);
    }

    apply_result_dec_ref(z3context, result);
    goal_dec_ref(z3context, goal);
    tactic_dec_ref(z3context, tseitinTactic);
    return out_formula;
```

It is scary even if I remove the clean-up code.
